      ],
      "confidence": 0.85
    },
    {
      "type": "Host-level ICMP filtered (host firewall)",
      "cause": "The server at 172.16.0.12 may be up but blocking/ignoring ICMP (host firewall or OS-level filtering), causing all ICMP probes from the directly-connected router to fail",
      "evidence": [
        "Router2 (directly on 172.16.0.0/24) receives no ICMP response: \"Success rate is 0 percent (0/5)\"",
