    },
    {
      "type": "Host misconfiguration or local-link/switching issue",
      "cause": "The host may have an incorrect IP/mask, duplicate IP, wrong gateway, or there may be a switch-port/cabling problem between server and router causing ARP/Layer-2 connectivity failure",
      "evidence": [
